('business:4-4-consumer-law:match:b3cfb40c', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Law”?", "options": ["Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015."]}'::jsonb, '{"answer": 3, "explain": "“Consumer Law” means: The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015."}'::jsonb),
('business:4-4-consumer-law:match:2c51f48a', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Rights Act 2015”?", "options": ["Processes a business uses to check that all goods meet the required quality standards before reaching the customer.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015."]}'::jsonb, '{"answer": 2, "explain": "“Consumer Rights Act 2015” means: An act of parliament giving customers protection when buying goods and services: they must be of satisfactory quality, fit for purpose, and as described."}'::jsonb),
('business:4-4-consumer-law:match:00a8fb7a', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Satisfactory Quality”?", "options": ["Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival."]}'::jsonb, '{"answer": 1, "explain": "“Satisfactory Quality” means: Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid."}'::jsonb),
('business:4-4-consumer-law:match:5727102a', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fit for Purpose”?", "options": ["Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products."]}'::jsonb, '{"answer": 0, "explain": "“Fit for Purpose” means: Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it."}'::jsonb),
('business:4-4-consumer-law:match:cda1cf20', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “As Described”?", "options": ["Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement.", "Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015."]}'::jsonb, '{"answer": 2, "explain": "“As Described” means: Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement."}'::jsonb),
('business:4-4-consumer-law:match:d749cf3f', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reputation”?", "options": ["Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "Products that are faulty, unsafe, or fail to meet the legal standards set by the Consumer Rights Act 2015.", "Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival."]}'::jsonb, '{"answer": 3, "explain": "“Reputation” means: What customers say and feel about a business; damage to a reputation can seriously reduce sales and threaten business survival."}'::jsonb),
('business:4-4-consumer-law:match:a1e68ff5', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Compensation”?", "options": ["Goods must not be damaged or faulty when bought; the quality expected should reflect the price paid.", "The area of law that protects the customers of a business, mainly through the Consumer Rights Act 2015.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it."]}'::jsonb, '{"answer": 2, "explain": "“Compensation” means: A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987."}'::jsonb),
('business:4-4-consumer-law:match:e4d73b27', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer Protection Act 1987”?", "options": ["Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Goods must do what they are meant to do; if a seller claims a product performs a function, it must be able to do it.", "A payment made to a customer for loss or damage caused by a defective product, claimable under the Consumer Protection Act 1987."]}'::jsonb, '{"answer": 1, "explain": "“Consumer Protection Act 1987” means: Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury."}'::jsonb),
('business:4-4-consumer-law:match:5588fc2b', 'business', 'business:4-4-consumer-law', '4.4 Consumer Law', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “30-Day Return Rule”?", "options": ["Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products.", "Gives consumers the right to claim compensation if a defective product causes death, damage, or personal injury.", "Goods must be exactly as described or advertised — receiving the wrong colour or specification breaks this requirement.", "Online platforms that allow customers to publicly voice complaints about defective goods, rapidly damaging a business''s reputation."]}'::jsonb, '{"answer": 0, "explain": "“30-Day Return Rule” means: Customers may return faulty goods for a full refund within 30 days of purchase; this does NOT apply to downloaded digital products."}'::jsonb),
