('business:4-5-business-location:match:611b8683', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Location”?", "options": ["The place where a business is sited.", "Nearness to something — such as a market, raw materials, or a labour supply.", "Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull."]}'::jsonb, '{"answer": 0, "explain": "“Location” means: The place where a business is sited."}'::jsonb),
('business:4-5-business-location:match:53e784c4', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Proximity”?", "options": ["An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market.", "Materials that are processed in some way as part of the manufacture of a product.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport.", "Nearness to something — such as a market, raw materials, or a labour supply."]}'::jsonb, '{"answer": 3, "explain": "“Proximity” means: Nearness to something — such as a market, raw materials, or a labour supply."}'::jsonb),
('business:4-5-business-location:match:640267c3', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transport infrastructure”?", "options": ["An area near Cambridge with a high concentration of skilled ICT workers and technology firms.", "The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband.", "Materials that are processed in some way as part of the manufacture of a product.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport."]}'::jsonb, '{"answer": 1, "explain": "“Transport infrastructure” means: The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband."}'::jsonb),
('business:4-5-business-location:match:6d5e252b', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Enterprise zone”?", "options": ["A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses.", "An area near Cambridge with a high concentration of skilled ICT workers and technology firms.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport.", "The workers employed by a business to produce goods and services — a key factor of production."]}'::jsonb, '{"answer": 0, "explain": "“Enterprise zone” means: A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses."}'::jsonb),
('business:4-5-business-location:match:a7b19f9b', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Freeport”?", "options": ["Nearness to something — such as a market, raw materials, or a labour supply.", "An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market.", "The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband.", "Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs."]}'::jsonb, '{"answer": 1, "explain": "“Freeport” means: An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market."}'::jsonb),
('business:4-5-business-location:match:9d0a1952', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Northern Powerhouse”?", "options": ["A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses.", "Nearness to something — such as a market, raw materials, or a labour supply.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull.", "The place where a business is sited."]}'::jsonb, '{"answer": 2, "explain": "“Northern Powerhouse” means: A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull."}'::jsonb),
('business:4-5-business-location:match:55c120ab', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Silicon Fen”?", "options": ["An area near Cambridge with a high concentration of skilled ICT workers and technology firms.", "The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing.", "Nearness to something — such as a market, raw materials, or a labour supply.", "Materials that are processed in some way as part of the manufacture of a product."]}'::jsonb, '{"answer": 0, "explain": "“Silicon Fen” means: An area near Cambridge with a high concentration of skilled ICT workers and technology firms."}'::jsonb)
